"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Dropzone,
  DropzoneEmptyState,
  DropzoneContent,
} from "@/components/ui/shadcn-io/dropzone";
import { RollingUpdates } from "@/components/rolling-updates";

import { FileText, Image, Sparkles, Download } from "lucide-react";

import { Item, ItemMedia, ItemTitle, ItemContent } from "@/components/ui/item";
import { Loader2 } from "lucide-react"; // Import Loader2 for the activity indicator
import { Spinner } from "@/components/ui/spinner";

// --- New Component for Download Button ---
const DownloadButton = ({ downloadPath }: { downloadPath: string }) => (
  <div className="flex justify-center my-8">
    <a
      href={downloadPath}
      download
      className="
        inline-flex items-center justify-center 
        h-14 px-8 py-6 text-lg 
        rounded-xl shadow-lg hover:shadow-xl transition-all 
        text-white font-medium 
        bg-gradient-to-r from-green-500 to-teal-600 hover:from-green-600 hover:to-teal-700 
        focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500
      "
    >
      <Download className="w-5 h-5 mr-2" />
      Download Generated Document
    </a>
  </div>
);
// ------------------------------------------

export default function Home() {
  const [contextFiles, setContextFiles] = useState<File[]>([]);
  const [templateFile, setTemplateFile] = useState<File | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isStreaming, setIsStreaming] = useState<boolean>(false);

  const [modelUpdates, setModelUpdates] = useState<string[]>([]);

  const [downloadPath, setDownloadPath] = useState<string | null>(null);

  const formatUpdate = (updateString: string) => {
    const withoutQuotes = updateString.replace(/['"]/g, "");
    const lines = withoutQuotes.split(/\r?\n/);
    return lines;
  };

  const startStream = async () => {
    setError(null);
    setDownloadPath(null);
    setIsStreaming(true); // Set streaming to true when starting

    try {
      const form = new FormData();
      contextFiles.forEach((f) => form.append("contextFiles", f));
      // FormData.append for files can take the File object directly
      if (templateFile) {
        form.append("templateFiles", templateFile);
      } else {
        // Optionally handle this case, though the button is disabled if no template
        setError("Template file is missing.");
        setIsStreaming(false);
        return;
      }

      const res = await fetch("/api/upload", { method: "POST", body: form });

      if (!res.ok) {
        setError("Upload failed.");
        setIsStreaming(false);
        return;
      }

      const { jobId } = await res.json();

      const es = new EventSource(`/api/stream/${jobId}`);

      es.onopen = () => {
        console.log("EventSource connection opened");
      };

      es.onerror = (e) => {
        console.error("EventSource error:", e);
        if (es.readyState === EventSource.CLOSED && !downloadPath) {
          setError("Connection interrupted. The generation may have failed.");
          setIsStreaming(false);
        }
      };

      const eventTypes = [
        "response.code_interpreter_call_code.done",
        "response.output_text.done",
      ] as const;

      eventTypes.forEach((eventType) => {
        es.addEventListener(eventType, (e: MessageEvent) => {
          const raw = e.data ?? "";
          if (!raw) return;
          const update = JSON.parse(raw);
          console.log(`${eventType}: ${update}`);
          setModelUpdates((prev) => prev.concat(formatUpdate(update)));
        });
      });

      // COMPLETED – expose download link
      es.addEventListener("completed", (e: MessageEvent) => {
        const raw = e.data ?? "";
        if (!raw) setError("No file found");
        const filePath = JSON.parse(raw);
        console.log("Completed event received:", filePath);

        setDownloadPath(filePath);
        es.close();
        setIsStreaming(false);
      });

      // ERROR event from server
      es.addEventListener("error", (e: MessageEvent) => {
        console.error("Server error event:", e.data);
        setError(`Server error: ${e.data}`);
        setIsStreaming(false);
        es.close();
      });
    } catch (err) {
      console.error("Stream initialization error:", err);
      setError("Failed to start generation. Please try again.");
      setIsStreaming(false);
    }
  }; // End of startStream

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50">
      {/* Header */}
      <div className="bg-white/80 backdrop-blur-sm border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-6 py-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg flex items-center justify-center">
              <Sparkles className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-2xl font-bold text-slate-900">
              Document Generator
            </h1>
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 py-12">
        {/* Instructions Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 mb-8">
          <h2 className="text-lg font-semibold text-slate-900 mb-3">
            How it works
          </h2>
          <div className="flex flex-col md:flex-row gap-6 text-sm text-slate-600">
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                1
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">
                  Add context
                </div>
                Upload images or documents for reference
              </div>
            </div>
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                2
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">
                  Choose template
                </div>
                Upload your document template
              </div>
            </div>
            <div className="flex gap-3 flex-1">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-semibold flex-shrink-0">
                3
              </div>
              <div>
                <div className="font-medium text-slate-900 mb-1">Generate</div>
                Let AI create your document
              </div>
            </div>
          </div>
        </div>

        {/* Upload Section */}
        <div className="grid md:grid-cols-2 gap-6 mb-8">
          {/* Context Files */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4">
              <Image className="w-5 h-5 text-slate-600" />
              <h3 className="text-lg font-semibold text-slate-900">
                Context Files
              </h3>
              <span className="text-xs text-slate-500 ml-auto">Optional</span>
            </div>
            <Dropzone
              maxFiles={100}
              onDrop={setContextFiles}
              src={contextFiles}
              className="border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50/50 transition-all rounded-xl bg-slate-50/50"
            >
              <DropzoneEmptyState />
              <DropzoneContent />
            </Dropzone>
            {contextFiles.length > 0 && (
              <p className="text-sm text-slate-600 mt-3">
                {contextFiles.length} file
                {contextFiles.length !== 1 ? "s" : ""} added
              </p>
            )}
          </div>

          {/* Template File */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4">
              <FileText className="w-5 h-5 text-slate-600" />
              <h3 className="text-lg font-semibold text-slate-900">
                Template File
              </h3>
              <span className="text-xs text-red-500 ml-auto">Required</span>
            </div>
            <Dropzone
              maxFiles={1}
              onDrop={(files) => setTemplateFile(files[0] || null)}
              src={templateFile ? [templateFile] : []}
              className="border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50/50 transition-all rounded-xl bg-slate-50/50"
            >
              <DropzoneEmptyState />
              <DropzoneContent />
            </Dropzone>
            {templateFile && (
              <p className="text-sm text-slate-600 mt-3">
                {templateFile.name}
              </p>
            )}
          </div>
        </div>

        {/* Error Display */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-xl p-4 mb-6">
            <p className="text-sm text-red-800">{error}</p>
          </div>
        )}

        {/* Primary Action Button: Generate / Download */}
        {downloadPath ? (
          // New Download Button is rendered when downloadPath is available
          <DownloadButton downloadPath={downloadPath} />
        ) : (
          // Existing Generate Button
          <div className="flex justify-center mb-8">
            <Button
              onClick={startStream}
              // Disable if streaming or no template file
              disabled={isStreaming || !templateFile}
              size="lg"
              className="bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white px-8 py-6 text-lg rounded-xl shadow-lg hover:shadow-xl transition-all disabled:opacity-50"
            >
              {isStreaming ? (
                <>Processing...</>
              ) : (
                <>
                  <Sparkles className="w-5 h-5 mr-2" />
                  Generate Document
                </>
              )}
            </Button>
          </div>
        )}

        {/* Output Section */}
        {isStreaming && 
              <Item
              variant="muted"
              className="
                border border-slate-300
                shadow-none
                bg-slate-50/50
                rounded-xl
              "
            >
              {/* Use the Activity Indicator in the ItemMedia slot */}
              <ItemMedia>
                <Loader2
          className="size-8 text-blue-500 animate-spin animate-[pulse_2s_cubic-bezier(0.4,_0,_0.6,_1)_infinite]"
        />
              </ItemMedia>
              <ItemContent>
                {/* Use the first line as a static header/status */}
                <ItemTitle className="text-sm text-slate-500 font-medium">
                  AI thoughts...
                </ItemTitle>
                {/* Use the second line for the actual rolling updates */}
                <ItemTitle className="text-base text-slate-800 font-medium mt-1">
                <RollingUpdates updates={modelUpdates} />
                </ItemTitle>
              </ItemContent>
            </Item>
    }
      </div>
    </div>
  );
}